#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

typedef struct Node {
    int data;
    struct Node *next;
} Node;

// 1. The Naive Standard Appender: O(N) Time
// Must traverse the entire list just to add to the end.
void append_naive(Node **head, int val) {
    Node *new_node = malloc(sizeof(Node));
    new_node->data = val;
    new_node->next = NULL;

    if (*head == NULL) {
        *head = new_node;
        return;
    }

    Node *curr = *head;
    while (curr->next != NULL) curr = curr->next; // O(N) Traversal
    curr->next = new_node;
}

// 2. The Professional Appender: O(1) Time
// Elite lists always track a 'tail' pointer to bypass the O(N) traversal.
typedef struct {
    Node *head;
    Node *tail;
} List;

void append_fast(List *list, int val) {
    Node *new_node = malloc(sizeof(Node));
    new_node->data = val;
    new_node->next = NULL;

    if (list->tail == NULL) {
        list->head = new_node;
        list->tail = new_node;
    } else {
        list->tail->next = new_node;
        list->tail = new_node; // Instantly O(1) append
    }
}

