// Engineer attempts to delete a node by value
void delete_node(Node **head, int target) {
    Node *curr = *head;
    Node *prev = NULL;

    while (curr != NULL) {
        if (curr->data == target) {
            // DANGER: We found it. Link the previous node to the next node.
            prev->next = curr->next;
            free(curr);
            return;
        }
        prev = curr;
        curr = curr->next;
    }
}

