struct list_head {
    struct list_head *next;
    struct list_head *prev;
};

// 2. The Application Data
typedef struct {
    int sensor_id;
    float temperature;

    // The routing logic is embedded directly into the physical memory
    // of the data struct. No external Node required.
    struct list_head list;
} SensorRecord;

// 3. A totally generic addition function.
// It only cares about linking the list_head addresses.
void list_add(struct list_head *new_node, struct list_head *head) {
    new_node->next = head->next;
    new_node->prev = head;

    if (head->next) head->next->prev = new_node;
    head->next = new_node;
}

